+fn arb_checked_range() -> impl Strategy<Value = CheckedRange> {
+    (0_u64..50_000, 50_000_u64..100_000, 0_u64..50_000)
+        .prop_map(|(start, end, checked)| CheckedRange {
+            start_ordinal: start,
+            end_ordinal: end,
