+fn arb_offset_mismatch() -> impl Strategy<Value = OffsetMismatch> {
+    ("[a-z0-9-]{8,24}", 0_u64..100_000, 0_u64..100_000)
+        .prop_map(|(event_id, expected_offset, actual_offset)| OffsetMismatch {
+            event_id,
+            expected_offset,
+            actual_offset,
+        })
+}
